        public static bool DirectViewOne(Control oDisplay, string ViewID, ref DataTable dt, bool bIcon, bool bBGColor, DirectViewCond[] Cond, bool bColumnFit, bool bAutoSort, ref string sSql)
        {
            int i;
            int iBGIndex;
            int iFirstIndex;
            int iIndex;
            int iSortIndWidth = 0;
            int iColWidth;
            int iDataWidth;
            int itemWidth = 0;

            string s_column = "";
            string sColor;

            FarPoint.Win.Spread.CellType.NumberCellType numCell = new FarPoint.Win.Spread.CellType.NumberCellType();
           

            try
            {
                numCell.DecimalPlaces = 3;
                numCell.ShowSeparator = true;
                numCell.FixedPoint = false;


                //Get Data from server. 
                //Currently no meaning for sql. it work with 'View ID'
                if (GetDataOne(s_column, ref dt, ViewID, Cond, bIcon, bBGColor, ref sSql) == false)
                    return false;

                //Target Object Spread case
                if (oDisplay is FarPoint.Win.Spread.FpSpread)
                {
                    //Convert object type
                    FarPoint.Win.Spread.FpSpread spdDisplay;
                    spdDisplay = (FarPoint.Win.Spread.FpSpread)oDisplay;

                    //Initialize Spread
                    spdDisplay.ActiveSheet.RowCount = 0;
                   

                    if (dt.Rows.Count == 0)
                        return true;

                    //Bind Data Table
                    
                    spdDisplay.ActiveSheet.ColumnCount = 0;
                    spdDisplay.DataSource = null;
                    spdDisplay.DataSource = dt;


                    //Get first column index (Icon data column, BackColor data column) 
                    iFirstIndex = 0;
                    //if (bIcon == true)
                    if (bUseIcon == true)
                        iFirstIndex++;

                    //if (bBGColor == true)
                    if (bUseBGColor == true)
                        iFirstIndex++;


                    //Display Icon and Back Color
                    //if (bIcon == true)
                    if (bUseIcon == true || bUseBGColor == true)
                    {
                        FarPoint.Win.Spread.CellType.ImageCellType imgCellType = new FarPoint.Win.Spread.CellType.ImageCellType();

                        //Add Icon Column
                        spdDisplay.ActiveSheet.Columns.Add(0, 1);
                        spdDisplay.ActiveSheet.Columns[0].CellType = imgCellType;
                        spdDisplay.ActiveSheet.ColumnHeader.Cells[0, 0].Text = "-";

                        TPDR.initImage();

                        //Get Image list from Main screen
                        ImageList iTemp = MPGV.gIMdiForm.GetSmallIconList();  

                        for (i = 0; i < spdDisplay.ActiveSheet.RowCount; i++)
                        {
                            //Apply Icon image
                            if(bUseIcon == true)
                            {
                                spdDisplay.ActiveSheet.Cells[i, 0].Value = iTemp.Images[gTRSImage.GetInt(dt.Rows[i].ItemArray.GetValue(0).ToString())];
                            }

                            //Apply Background color
                            //if (bBGColor == true)
                            if (bUseIcon == true && bUseBGColor == true)
                            {
                                sColor = dt.Rows[i].ItemArray.GetValue(1).ToString();
                                if (MPCF.Trim(sColor) != "")
                                    spdDisplay.ActiveSheet.Rows[i].BackColor = Color.FromName(dt.Rows[i].ItemArray.GetValue(1).ToString());
                            }
                            else if (bUseIcon == false && bUseBGColor == true)
                            {
                                sColor = dt.Rows[i].ItemArray.GetValue(0).ToString();
                                if (MPCF.Trim(sColor) != "")
                                    spdDisplay.ActiveSheet.Rows[i].BackColor = Color.FromName(dt.Rows[i].ItemArray.GetValue(0).ToString());
                            }
                        }

                        //Remove Icon and Background color data column
                        //if (bIcon == true)
                        if (bUseIcon == true)
                            spdDisplay.ActiveSheet.Columns[1].Remove();
                        //if (bBGColor == true)
                        if (bUseIcon == true && bUseBGColor == true)
                        {
                            spdDisplay.ActiveSheet.Columns[1].Remove();
                        }
                        else if (bUseIcon == false && bUseBGColor == true)
                        {
                            spdDisplay.ActiveSheet.Columns[0].Remove();
                            spdDisplay.ActiveSheet.Columns[0].Remove();
                        }
                            
                    }

                    for (i = 0; i < spdDisplay.ActiveSheet.ColumnCount; i++)
                    {
                        // Header Caption 

                        //spdDisplay.ActiveSheet.ColumnHeader.Cells[0, i].Text = GenCaptionText(spdDisplay.ActiveSheet.ColumnHeader.Cells[0, i].Text);

                        spdDisplay.ActiveSheet.Columns[i].Label = GenCaptionText(spdDisplay.ActiveSheet.Columns[i].Label);

                        if (spdDisplay.Sheets[0].Columns[i].CellType is FarPoint.Win.Spread.CellType.NumberCellType)
                        {                            
                            spdDisplay.Sheets[0].Columns[i].CellType = numCell;
                        }
                    }

                    //Fit column size with maximum data length.
                    //Can not use function MPCF.FitColumnHeader  -> Too slow

                    //MPCF.FitColumnHeader(spdDisplay);
                    if (bColumnFit == true)
                    {
                        Graphics g = spdDisplay.CreateGraphics();

                        for (i = 0; i < spdDisplay.ActiveSheet.ColumnCount; i++)
                        {
                            itemWidth = 0;
                            //Fit Icon column size
                            //if (i == 0 && bIcon == true)
                            if (i == 0 && bUseIcon == true)
                            {
                                spdDisplay.ActiveSheet.Columns[0].Width = spdDisplay.ActiveSheet.GetPreferredColumnWidth(0, false, false, false);
                                continue;
                            }

                            if (bAutoSort == true)
                                iSortIndWidth = 10;
                            else
                                iSortIndWidth = 0;

                                for (int j = 0; j < spdDisplay.ActiveSheet.RowCount; j++)
                                {
                                    iIndex = i;
                                     
                                    if (bUseIcon == true)
                                        iIndex = i - 1;

                                    //if (bUseBGColor == true)
                                    //    iIndex = i + 1;
                                    iDataWidth = System.Convert.ToInt32(g.MeasureString(spdDisplay.ActiveSheet.Cells[j, i].Text, spdDisplay.Font).Width) + MPGC.LV_BONUS_COLUMN_WIDTH;
                                    iColWidth = System.Convert.ToInt32(g.MeasureString(spdDisplay.ActiveSheet.Columns[i].Label, spdDisplay.Font).Width) + MPGC.LV_BONUS_COLUMN_WIDTH + iSortIndWidth;

                                    if (iColWidth < iDataWidth)
                                        iColWidth = iDataWidth;

                                    if (iColWidth > itemWidth)
                                        itemWidth = iColWidth;

                                    //if (System.Convert.ToInt32(g.MeasureString(spdDisplay.ActiveSheet.Cells[j, i].Text, spdDisplay.Font).Width) + MPGC.LV_BONUS_COLUMN_WIDTH + iSortIndWidth > itemWidth)
                                    //    itemWidth = System.Convert.ToInt32(g.MeasureString(spdDisplay.ActiveSheet.Cells[j, i].Text, spdDisplay.Font).Width) + MPGC.LV_BONUS_COLUMN_WIDTH + iSortIndWidth;

                                    ////compare with column header text
                                    //if (System.Convert.ToInt32(g.MeasureString(dt.Columns[iFirstIndex + iIndex].ColumnName, spdDisplay.Font).Width) + MPGC.LV_BONUS_COLUMN_WIDTH + iSortIndWidth > itemWidth)
                                    //    itemWidth = System.Convert.ToInt32(g.MeasureString(dt.Columns[iFirstIndex + iIndex].ColumnName, spdDisplay.Font).Width) + MPGC.LV_BONUS_COLUMN_WIDTH + iSortIndWidth;

                                }
                            spdDisplay.ActiveSheet.Columns[i].Width = (int)itemWidth;

                            //Vertical Alignment to Center
                            spdDisplay.ActiveSheet.Columns[i].VerticalAlignment = FarPoint.Win.Spread.CellVerticalAlignment.Center;
                        }

                        g.Dispose();
                    }

                    // Add Auto Sort Option to Spread
                    if (bAutoSort == true)
                    {
                        for (i = 0; i < spdDisplay.ActiveSheet.ColumnCount; i++)
                        {
                            spdDisplay.ActiveSheet.Columns[i].AllowAutoSort = true;
                            //sheetX.Columns[i].SortIndicator = FarPoint.Win.Spread.Model.SortIndicator.None;
                            //sheetX.Columns[i].ShowSortIndicator = false;
                            //sheetX.SetColumnShowSortIndicator(i, false);
                            spdDisplay.ActiveSheet.Columns[i].Width += 15;
                        }
                    }

                    return true;
                }

                //List View Object
                else if (oDisplay is ListView)
                {
                    ListView lisDisplay;
                    lisDisplay = (ListView)oDisplay;

                    //Initialize List View
                    MPCF.InitListView(lisDisplay);
                    lisDisplay.Columns.Clear();

                    if (dt.Rows.Count == 0)
                        return true;

                   

                    //Get Image list from main screen
                    lisDisplay.SmallImageList = MPGV.gIMdiForm.GetSmallIconList();


                    //Get first column index (Icon data column, BackColor data column) 
                    iBGIndex = 0;
                    iFirstIndex = 0;
                    //if (bIcon == true)
                    if (bUseIcon == true)
                        iFirstIndex++;

                    //if (bBGColor == true)
                    if (bUseBGColor == true)
                    {
                        iFirstIndex++;
                        iBGIndex = iFirstIndex - 1;
                    }

                    //Make column header
                    for (i = iFirstIndex; i < dt.Columns.Count; i++)
                    {
                        lisDisplay.Columns.Add(GenCaptionText(dt.Columns[i].ColumnName));
                    }

                    //Display Data, Icon, Background color by each recored
                    foreach (DataRow dr in dt.Rows)
                    {
                        ListViewItem itemX = new ListViewItem();

                        //Display Icon
                        //if (bIcon == true)
                        if (bUseIcon == true)
                            itemX = new ListViewItem(dr[iFirstIndex].ToString(), MPCF.ToInt(gTRSImage.GetInt(dr[0].ToString())));
                        else
                            itemX = new ListViewItem(dr[iFirstIndex].ToString());

                        //Display Background Color for first column
                        //if (bBGColor == true && MPCF.Trim(dr[iBGIndex].ToString()) != "")
                        if (bUseBGColor == true && MPCF.Trim(dr[iBGIndex].ToString()) != "")
                            itemX.BackColor = Color.FromName(dr[iBGIndex].ToString());

                        //Display Background Color from second column
                        for (i = iFirstIndex+1; i < dt.Columns.Count; i++)
                        {
                            string sTemp = dr[iBGIndex].ToString();
                            //if (bBGColor == true && MPCF.Trim(dr[iBGIndex].ToString()) != "")
                            if (bUseBGColor == true && MPCF.Trim(dr[iBGIndex].ToString()) != "")
                                itemX.SubItems.Add(dr[i].ToString(), Color.Black, Color.FromName(dr[iBGIndex].ToString()), null);
                            else
                                itemX.SubItems.Add(dr[i].ToString());
                        }

                        lisDisplay.Items.Add(itemX);
                    }

                    if (bColumnFit)
                    {
                        MPCF.FitColumnHeader(lisDisplay);
                        Graphics g = lisDisplay.CreateGraphics();

                        for (i = 0; i < lisDisplay.Columns.Count; i++)
                        {
                            itemWidth = 0;
                            for (int j = 0; j < lisDisplay.Items.Count; j++)
                            {
                                iIndex = i;

                                if (i == 0)
                                    iDataWidth = System.Convert.ToInt32(g.MeasureString(lisDisplay.Items[j].SubItems[i].Text, lisDisplay.Font).Width) + MPGC.LV_BONUS_COLUMN_WIDTH + lisDisplay.SmallImageList.ImageSize.Width;
                                else
                                    iDataWidth = System.Convert.ToInt32(g.MeasureString(lisDisplay.Items[j].SubItems[i].Text, lisDisplay.Font).Width) + MPGC.LV_BONUS_COLUMN_WIDTH;
                                iColWidth = System.Convert.ToInt32(g.MeasureString(lisDisplay.Columns[i].Text, lisDisplay.Font).Width) + MPGC.LV_BONUS_COLUMN_WIDTH + MPGC.LV_BONUS_COLUMN_WIDTH_WITH_IMAGE;

                                if (iColWidth < iDataWidth)
                                    iColWidth = iDataWidth;

                                if (iColWidth > itemWidth)
                                    itemWidth = iColWidth;
                            }

                            lisDisplay.Columns[i].Width = (int)itemWidth + MPGC.LV_BONUS_COLUMN_WIDTH_WITH_IMAGE;
                        }

                        g.Dispose();
                    }
                    //Remove Icon and Background Color data column
                    //lisDisplay.Columns[0].Text = lisDisplay.Columns[iFirstIndex].Text;
                    //for (i = iFirstIndex; i > 0; i--)
                    //    lisDisplay.Columns.Remove(lisDisplay.Columns[i]);

                }

                return true;
            }
            catch (Exception ex)
            {
                MPCF.ShowMsgBox(ex.Message);
                return false;
            }


        }

        public static string GenCaptionText(string sOrgText)
        {
            int j;
            int iTotal;
            string sTemp = string.Empty;
            string sTarget = string.Empty;

            bool bSpace;

            try
            {
                if (MPCF.Trim(sOrgText) == "")
                    return " ";

                sTemp = MPCF.Trim(sOrgText);
                sTemp = sTemp.Replace("_", " ");
                sTemp = MPCF.ToLower(sTemp);

                iTotal = sTemp.Length;

                sTarget = MPCF.ToUpper(sTemp.Substring(0, 1));
                bSpace = false;

                for (j = 1; j < iTotal; j++)
                {
                    if (sTemp.Substring(j, 1) == " ")
                    {
                        sTarget = sTarget + " ";
                        bSpace = true;
                        continue;
                    }

                    if (bSpace == true)
                    {
                        sTarget = sTarget + MPCF.ToUpper(sTemp.Substring(j, 1));
                        bSpace = false;
                    }
                    else
                        sTarget = sTarget + sTemp.Substring(j, 1);
                }
                sTarget = sTarget.Replace(" Id ", " ID ");
                if (sTarget.Length > 3)
                {
                    if (sTarget.Substring(sTarget.Length - 3, 3) == " Id")
                        sTarget = sTarget.Substring(0, sTarget.Length - 3) + " ID";
                }

                sTarget = MPCF.FindLanguage(sTarget, CAPTION_TYPE.LABEL);

                return sTarget;
            }
            catch (Exception ex)
            {
                MPCF.ShowMsgBox(ex.Message);
                return sTarget;
            }
        }

        private static string SetParamType(object sParamValue)
        {
            string sTypeName;

            sTypeName = sParamValue.GetType().Name;

            if (sTypeName == "Int16" || sTypeName == "Int32" || sTypeName == "Int64")
                return "INT";
            else if (sTypeName == "Double")
                return "DOUBLE";
            else if (sTypeName == "Single")
                return "FLOAT";
            else if (sTypeName == "Char")
                return "STRING";
            else if (sTypeName == "Table")
                return "TABLE";
            else
                return "STRING";
        }

