        public static bool DirectView(Control oDisplay, string ViewID, ref DataTable dt, bool bIcon, bool bBGColor,bool bColumnFit, params string[] Cond)
        {
            //TRSNode in_node;
            //TRSNode out_node;

            DataTable dt2 = new DataTable();

            int i;
            int iBGIndex;
            int iFirstIndex;
            float icolwidth;
            //float iSortIndSize;

            string s_column="";
            string s_sql="";
            string s_replace="";
            string sColor;

            bool bUserHeader = false;

            try
            {
                s_sql = "SELECT W.VIEW_ID,W.COL_NAME, DECODE(W.DISPLAY_NAME,' ', W.COL_NAME, W.DISPLAY_NAME), W.COL_DESC, TO_CHAR(NVL(U.COL_SEQ,99999)), ";
                s_sql = s_sql + " V.SQL_1, V.SQL_2, V.SQL_3, V.SQL_4, V.SQL_5, V.SQL_6, V.SQL_7, V.SQL_8, V.SQL_9, V.SQL_10 ";
                s_sql = s_sql + " FROM MTAPDVWHDR W, MTAPDVUHDR U, MTAPSQLDEF V ";
                s_sql = s_sql + " WHERE 1=1 ";
                s_sql = s_sql + " AND W.VIEW_ID=U.VIEW_ID(+) ";
                s_sql = s_sql + " AND W.COL_NAME = U.COL_NAME(+) ";
                s_sql = s_sql + " AND W.VIEW_ID='"+ViewID+"'";
                s_sql = s_sql + " AND U.VIEW_ID(+)='"+ViewID+"' ";
                s_sql = s_sql + " AND U.FACTORY(+)='"+MPGV.gsFactory+"' ";
                s_sql = s_sql + " AND U.USER_ID(+)='"+MPGV.gsUserID+"' ";
                s_sql = s_sql + " AND V.VIEW_ID='" + ViewID + "' ";
                s_sql = s_sql + " ORDER BY U.COL_SEQ ";

                 if (GetData(s_sql, ref dt2) == false)
                 {
                     dt2.Dispose();
                    return false;
                 }

                if (dt2.Rows[0].ItemArray[4].ToString() != "99999")
                    bUserHeader = true;
                else
                    bUserHeader = false;
                s_column = "SELECT";
                for (i = 0; i < dt2.Rows.Count; i++)
                {
                    if (bUserHeader == true && dt2.Rows[i].ItemArray[4].ToString() == "99999")
                        continue;

                    s_column = s_column + " " + dt2.Rows[i].ItemArray[1].ToString() + " ";
                    s_column = s_column + "\"" + dt2.Rows[i].ItemArray[2].ToString() + "\",";
                }

                s_column = s_column.Substring(0, s_column.Length - 1);
                s_column = s_column + " FROM ( ";

               
                s_sql="";
                s_sql = s_sql + dt2.Rows[0].ItemArray[5].ToString();
                s_sql = s_sql + dt2.Rows[0].ItemArray[6].ToString();
                s_sql = s_sql + dt2.Rows[0].ItemArray[7].ToString();
                s_sql = s_sql + dt2.Rows[0].ItemArray[8].ToString();
                s_sql = s_sql + dt2.Rows[0].ItemArray[9].ToString();
                s_sql = s_sql + dt2.Rows[0].ItemArray[10].ToString();
                s_sql = s_sql + dt2.Rows[0].ItemArray[11].ToString();
                s_sql = s_sql + dt2.Rows[0].ItemArray[12].ToString();
                s_sql = s_sql + dt2.Rows[0].ItemArray[13].ToString();
                s_sql = s_sql + dt2.Rows[0].ItemArray[14].ToString();
                
                if (Cond != null)
                {
                    for (i = 0; i < Cond.Length; i++)
                    {
                        s_replace = "$C_" + i.ToString();
                        s_sql.Replace(s_replace, Cond[i]);
                    }
                }
                s_column = s_column + s_sql;
                s_column = s_column + " )";

                if (GetData(s_column, ref dt) == false)
                    return false;

                
                if (oDisplay is FarPoint.Win.Spread.FpSpread)
                {
                    FarPoint.Win.Spread.FpSpread spdDisplay;
                    spdDisplay = (FarPoint.Win.Spread.FpSpread)oDisplay;
                    spdDisplay.DataSource = dt;

                    
                    if (bIcon == true)
                    {
                        FarPoint.Win.Spread.CellType.ImageCellType imgCellType = new FarPoint.Win.Spread.CellType.ImageCellType();

                        spdDisplay.ActiveSheet.Columns.Add(0, 1);
                        spdDisplay.ActiveSheet.Columns[0].CellType = imgCellType;
                        spdDisplay.ActiveSheet.ColumnHeader.Cells[0, 0].Text = "-";

                        ImageList iTemp = MPGV.gIMdiForm.GetSmallIconList();

                        for (i = 0; i < spdDisplay.ActiveSheet.RowCount; i++)
                        {
                            spdDisplay.ActiveSheet.Cells[i, 0].Value = iTemp.Images[gTRSImage.GetInt(dt.Rows[i].ItemArray.GetValue(0).ToString())];

                            if (bBGColor == true)
                            {
                                sColor = dt.Rows[i].ItemArray.GetValue(1).ToString();
                                if (MPCF.Trim(sColor) != "")
                                    spdDisplay.ActiveSheet.Rows[i].BackColor = Color.FromName(dt.Rows[i].ItemArray.GetValue(1).ToString());
                            }
                        }
                        
                    }
                    else if (bBGColor == true)
                    {
                        sColor = dt.Rows[i].ItemArray.GetValue(0).ToString();
                        if (MPCF.Trim(sColor) != "")
                            spdDisplay.ActiveSheet.Rows[i].BackColor = Color.FromName(dt.Rows[i].ItemArray.GetValue(0).ToString());
                    }

                    if (bIcon == true)
                        spdDisplay.ActiveSheet.Columns[1].Remove();
                    if (bBGColor == true)
                        spdDisplay.ActiveSheet.Columns[1].Remove();

                    if (bColumnFit == true)
                    {
                        for (i = 0; i < spdDisplay.ActiveSheet.ColumnCount; i++)
                        {
                            icolwidth = spdDisplay.ActiveSheet.GetPreferredColumnWidth(i, false, false, false);
                            spdDisplay.ActiveSheet.Columns[i].Width = icolwidth;
                            spdDisplay.ActiveSheet.Columns[i].VerticalAlignment = FarPoint.Win.Spread.CellVerticalAlignment.Center;
                        }
                    }


                }
                else if(oDisplay is ListView)
                {
                    ListView lisDisplay;
                    lisDisplay = (ListView)oDisplay;

                    MPCF.InitListView(lisDisplay);
                    lisDisplay.Columns.Clear();

                    if (dt.Rows.Count == 0)
                        return true;

                    for(i=0;i<dt.Columns.Count;i++)
                    {
                        lisDisplay.Columns.Add(dt.Columns[i].ColumnName);
                    }
                    lisDisplay.SmallImageList = MPGV.gIMdiForm.GetSmallIconList();

                    iBGIndex = 0;
                    iFirstIndex = 0;

                    if (bIcon == true)
                        iFirstIndex++;

                    if (bBGColor == true)
                    {
                        iFirstIndex++;
                        iBGIndex = iFirstIndex - 1;
                    }

                    foreach (DataRow dr in dt.Rows)
                    {
                        ListViewItem itemX = new ListViewItem();

                        
                        if(bIcon==true)
                        {
                            itemX = new ListViewItem(dr[iFirstIndex].ToString(), MPCF.ToInt(gTRSImage.GetInt(dr[0].ToString())));
                        }
                        else
                        {
                            itemX = new ListViewItem(dr[iFirstIndex].ToString());
                        }

                        if (bBGColor == true && MPCF.Trim(dr[iBGIndex].ToString()) != "")
                            itemX.BackColor = Color.FromName(dr[iBGIndex].ToString());

                        
                        for (i = 1; i < dt.Columns.Count; i++)
                        {
                            //itemX.SubItems.Add(dr[i].ToString());

                            if (bBGColor == true && MPCF.Trim(dr[iBGIndex].ToString()) != "")
                                itemX.SubItems.Add(dr[i].ToString(), Color.Black, Color.FromName(dr[iBGIndex].ToString()), null);
                            else
                                itemX.SubItems.Add(dr[i].ToString());
                        }
                        lisDisplay.Items.Add(itemX); 
                    }
                    lisDisplay.Columns[0].Text = lisDisplay.Columns[iFirstIndex].Text;

                    
                    for (i = iFirstIndex; i > 0; i--)
                        lisDisplay.Columns.Remove(lisDisplay.Columns[i]);

                    if (bColumnFit == true)
                    {
                        MPCF.FitColumnHeader(lisDisplay);
                    }
                }    
                


                return true;
            }
            catch (Exception ex)
            {
                MPCF.ShowMsgBox(ex.Message);
                return false;
            }

            
        }
