                        }
                        //2011.02.22 Blocked by BSCHO, 만건이상 조회시 에러 발생되는것 막음
                        //if (_Out.h_status_value != '0')
                        //{
                        //    MessageBox.Show(_Out.h_msg);
                        //    return null;
                        //}
                        BinaryDataZip = new byte[_Out.data_count];
                        for (i = 0; i < _Out.data_count; i++)
                        {
                            BinaryDataZip[i] = (byte)_Out.data_tbl[i].data;
                        }

                        DataDecompress(BinaryDataZip, ref BinaryData, _Out.binary_length);

                        if (deserializeFromBinary(BinaryData, ref dt2) == false)
                        {
                            return false;
                        }
                        GC.Collect();
                        GC.GetTotalMemory(true);
                        foreach (DataRow dr in dt2.Rows)
                        {
                            dt.Rows.Add(dr.ItemArray);
                        }
                        _In.next_row = _Out.next_row;
                        if (dt2 != null) { dt2.Clear();  dt2.Dispose(); dt2 = null; }
                    } while (_Out.next_row > 0);
                }
                _Out.data_tbl = null;
                _Out = null;
                GC.Collect();
                GC.GetTotalMemory(true);
                return true;
                #endregion
            }
            catch (Exception ex)
            {
                _Out.data_tbl = null;
                _Out = null;
                GC.Collect();
                GC.GetTotalMemory(true);
                throw ex;
                //return false;
            }
            finally
            {


                if (BinaryData != null) { BinaryData.Initialize(); BinaryData = null; }
                if (BinaryDataZip != null) { BinaryDataZip.Initialize(); BinaryDataZip = null; }
                if (dt2 != null) { dt2.Dispose(); dt2 = null; }
                TPDR.giMaxDataConut = TPDR.DEFAULT_MAX_DATA_COUNT;
                GC.Collect();
                GC.GetTotalMemory(true);
            }
            
        }
        public static void SetDirectViewCondition(string sViewID, Object oTemp)
        {
            TRSNode in_node = new TRSNode("VIEW_DIRECT_VIEW_CONDITION_LIST_IN");
            TRSNode out_node = new TRSNode("VIEW_DIRECT_VIEW_CONDITION_LIST_OUT");
            int i;
            int iRow=0;
            FarPoint.Win.Spread.FpSpread spdCondition;

            try
            {
                spdCondition = (FarPoint.Win.Spread.FpSpread)oTemp;
                spdCondition.Sheets[0].RowHeader.ColumnCount = 0;
                spdCondition.Sheets[0].RowCount = 0;
                spdCondition.Sheets[0].ColumnCount = 0;
                spdCondition.Sheets[0].ColumnHeader.Columns.Count = 0;
                spdCondition.Sheets[0].ColumnHeader.RowCount = 0;
                spdCondition.Sheets[0].ColumnHeader.Columns.Count=6;
                spdCondition.Sheets[0].ColumnHeader.RowCount = 1;
                
                spdCondition.Sheets[0].ColumnHeader.Cells[0, 0].Text = "Condition";
                spdCondition.Sheets[0].ColumnHeader.Cells[0, 1].Text = "Value";
                spdCondition.Sheets[0].ColumnHeader.Cells[0, 1].ColumnSpan = 2;

                spdCondition.Sheets[0].ColumnHeader.Cells[0, 3].Text = "Condition";
                spdCondition.Sheets[0].ColumnHeader.Cells[0, 4].Text = "Value";
                spdCondition.Sheets[0].ColumnHeader.Cells[0, 4].ColumnSpan = 2;

                spdCondition.Sheets[0].Columns[0].VerticalAlignment = FarPoint.Win.Spread.CellVerticalAlignment.Center;
                spdCondition.Sheets[0].Columns[1].VerticalAlignment = FarPoint.Win.Spread.CellVerticalAlignment.Center;
                spdCondition.Sheets[0].Columns[2].VerticalAlignment = FarPoint.Win.Spread.CellVerticalAlignment.Center;
                spdCondition.Sheets[0].Columns[3].VerticalAlignment = FarPoint.Win.Spread.CellVerticalAlignment.Center;
                spdCondition.Sheets[0].Columns[4].VerticalAlignment = FarPoint.Win.Spread.CellVerticalAlignment.Center;
                spdCondition.Sheets[0].Columns[5].VerticalAlignment = FarPoint.Win.Spread.CellVerticalAlignment.Center;


                MPCR.SetInMsg(in_node);
                in_node.ProcStep = '1';
                in_node.SetString("VIEW_ID", sViewID);

                Font ff = new Font("맑은 고딕", 8);

                do
                {

                    if (MPCR.CallService("TAP", "TAP_View_Direct_View_Condition_List", in_node, ref out_node) == false)
                    {
                        return;
                    }

                    for (i = 0; i < out_node.GetList("LIST").Count; i++)
                    {

                        iRow = (i) / 2;

                        if ((i+1) % 2 == 1)
                        {
                            spdCondition.Sheets[0].RowCount++;



                            if (out_node.GetList("LIST")[i].GetChar("REQ_FLAG") == 'Y')
                                spdCondition.Sheets[0].Cells[iRow, 0].Font = new Font(ff, FontStyle.Bold); ;

                            spdCondition.Sheets[0].Cells[iRow, 0].Text = "  " + out_node.GetList("LIST")[i].GetString("COND_DESC");
                            spdCondition.Sheets[0].Cells[iRow, 0].Tag = out_node.GetList("LIST")[i].GetString("COND_NAME");
                            spdCondition.Sheets[0].Cells[iRow, 0].BackColor = SystemColors.Control;
                            spdCondition.Sheets[0].Cells[iRow, 1].Tag = out_node.GetList("LIST")[i].GetString("DATA_TYPE");
                            if (out_node.GetList("LIST")[iRow].GetString("INPUT_TYPE") == "TextBox")
                            {
                                spdCondition.Sheets[0].Cells[iRow, 1].ColumnSpan = 2;
                                spdCondition.Sheets[0].Cells[iRow, 1].Column.Width = 200;
                            }
                            else
                            {
                                spdCondition.Sheets[0].Cells[iRow, 1].Column.Width = 200;
                                spdCondition.Sheets[0].Cells[iRow, 2].Tag = out_node.GetList("LIST")[i].GetString("DATA_TBL");
                                FarPoint.Win.Spread.CellType.ButtonCellType btn = new FarPoint.Win.Spread.CellType.ButtonCellType();
                                btn.Text = "...";
                                spdCondition.Sheets[0].Cells[iRow, 2].CellType = btn;
                                spdCondition.Sheets[0].Cells[iRow, 2].Column.Width = 20;
                            }

                            if (i == out_node.GetList("LIST").Count - 1)
                            {
                                spdCondition.Sheets[0].Cells[iRow, 3].ColumnSpan = 3;
                                spdCondition.Sheets[0].Cells[iRow, 3].BackColor = Color.DarkGray;
                            }
                        }
                        else
                        {
                            if (out_node.GetList("LIST")[i].GetChar("REQ_FLAG") == 'Y')
                                spdCondition.Sheets[0].Cells[iRow, 3].Font = new Font(frmAbout.DefaultFont, FontStyle.Bold); ;

                            spdCondition.Sheets[0].Cells[iRow, 3].Text = "  " + out_node.GetList("LIST")[i].GetString("COND_DESC");
                            spdCondition.Sheets[0].Cells[iRow, 3].Tag = out_node.GetList("LIST")[i].GetString("COND_NAME");
                            spdCondition.Sheets[0].Cells[iRow, 3].BackColor = SystemColors.Control;

                            spdCondition.Sheets[0].Cells[iRow, 4].Tag = out_node.GetList("LIST")[i].GetString("DATA_TYPE");
                            if (out_node.GetList("LIST")[i].GetString("INPUT_TYPE") == "TextBox")
                            {
                                spdCondition.Sheets[0].Cells[iRow, 4].Column.Width = 200;
                                spdCondition.Sheets[0].Cells[iRow, 4].ColumnSpan = 2;
                            }
                            else
                            {
                                spdCondition.Sheets[0].Cells[iRow, 4].Column.Width = 200;
                                spdCondition.Sheets[0].Cells[iRow, 5].Tag = out_node.GetList("LIST")[i].GetString("DATA_TBL");
                                FarPoint.Win.Spread.CellType.ButtonCellType btn = new FarPoint.Win.Spread.CellType.ButtonCellType();
                                btn.Text = "...";
                                spdCondition.Sheets[0].Cells[iRow, 5].CellType = btn;
                                spdCondition.Sheets[0].Cells[iRow, 5].Column.Width = 20;
                            }
                        }

                    }

                    in_node.SetInt("NEXT_COND_SEQ", out_node.GetInt("NEXT_COND_SEQ"));

                } while (in_node.GetInt("NEXT_COND_SEQ") != 0);


                return;
            }
            catch (Exception ex)
            {
                MPCF.ShowMsgBox(ex.Message);
                return;
            }
        }
    }
